INSERT INTO dbo.LicenseClasses( LicenseClassID, ClassName, ClassNameAR, ClassDescription, ClassDescriptionAR, MinimumAllowedAge, DefaultValidityLength, ClassFees ) VALUES ( 1, 'Class 1 - Small Motorcycle License', 'الفئة 1 - رخصة الدراجات النارية الصغيرة', 'It allows the owner to driver small motorcycle with small capacities and low power.', 'تتيح لحاملها قيادة الدراجة النارية الصغيرة ذات السعات الصغيرة والقدرة المحدودة.', 18, 5, 15);
INSERT INTO dbo.LicenseClasses( LicenseClassID, ClassName, ClassNameAR, ClassDescription, ClassDescriptionAR, MinimumAllowedAge, DefaultValidityLength, ClassFees ) VALUES ( 2, 'Class 2 - Heavy Motorcycle License', 'الفئة 2 - رخصة الدراجات النارية الثقيلة', 'It allows the owner to drive heavy motorcycles with large capacities and high power.', 'تتيح لحاملها قيادة الدراجات النارية الثقيلة ذات السعات الكبيرة والقدرة العالية.', 21, 5, 30);
INSERT INTO dbo.LicenseClasses( LicenseClassID, ClassName, ClassNameAR, ClassDescription, ClassDescriptionAR, MinimumAllowedAge, DefaultValidityLength, ClassFees ) VALUES ( 3, 'Class 3 - Ordinary Driving License', 'الفئة 3 - رخصة القيادة الاعتيادية', 'It allows the owner to drive ordinary vehicles such as private cars.', 'تتيح لمالكها قيادة المركبات العادية مثل السيارات الخاصة.', 18, 10, 20);
INSERT INTO dbo.LicenseClasses( LicenseClassID, ClassName, ClassNameAR, ClassDescription, ClassDescriptionAR, MinimumAllowedAge, DefaultValidityLength, ClassFees ) VALUES ( 4, 'Class 4 - Commerical Driving License', 'الفئة 4 - رخصة المركبات التجارية', 'It allows the owner to drive commercial vehicles such as taxis and limousines.', 'تتيح لمالكها قيادة المركبات التجارية مثل سيارات الأجرة والليموزين.', 21, 10, 200);
INSERT INTO dbo.LicenseClasses( LicenseClassID, ClassName, ClassNameAR, ClassDescription, ClassDescriptionAR, MinimumAllowedAge, DefaultValidityLength, ClassFees ) VALUES ( 5, 'Class 5 - Agricultural Driving License', 'الفئة 5 - رخصة الآلات الزراعية', 'It allows the owner to drive agricultural and work vehicles used in farming.', 'تتيح لمالكها قيادة الآلات الزراعية ومركبات العمل المستخدمة في الزراعة.', 21, 10, 50);
INSERT INTO dbo.LicenseClasses( LicenseClassID, ClassName, ClassNameAR, ClassDescription, ClassDescriptionAR, MinimumAllowedAge, DefaultValidityLength, ClassFees ) VALUES ( 6, 'Class 6 - Small & Medium Bus License', 'الفئة 6 - رخصة الحافلات الكبيرة والمتوسطة', 'It allows the owner to drive small and medium buses.', 'تتيح لمالكها قيادة الحافلات الصغيرة والمتوسطة.', 21, 10, 250);
INSERT INTO dbo.LicenseClasses( LicenseClassID, ClassName, ClassNameAR, ClassDescription, ClassDescriptionAR, MinimumAllowedAge, DefaultValidityLength, ClassFees ) VALUES ( 7, 'Class 7 - Truck & Heavy Vehcile License', 'الفئة 7 - رخصة الشاحنات والمركبات الثقيلة', 'It allows the owner to drive truck and heavy vehicles.', 'تتيح لمالكها قيادة الشاحنات والمركبات الثقيلة.', 21, 10, 300);
