INSERT INTO dbo.TestTypes( TestTypeID, TestTypeTitle, TestTypeTitleAR, TestTypeDescription, TestTypeDescriptionAR, TestTypeFees ) VALUES ( 1, 'Vision Test', 'اختبار النظر', 'This test assesses the applicant''s visual acuity to ensure they have sufficient vision to drive safely.', 'يقيس هذا الاختبار حدة البصر لدى المتقدم للتأكد من امتلاكه رؤية كافية للقيادة بأمان.', 10);
INSERT INTO dbo.TestTypes( TestTypeID, TestTypeTitle, TestTypeTitleAR, TestTypeDescription, TestTypeDescriptionAR, TestTypeFees ) VALUES ( 2, 'Written Test', 'الاختبار التحريري', 'This test assesses the applicant''s knowledge of traffic rules, road signs, and driving regulations. It typically consists of a number of multi-choice and written questions with a total marks of 100.', 'يقيس هذا الاختبار معرفة المتقدم بقواعد المرور وإشارات الطرق وأنظمة القيادة. ويتكون عادةً من عدد من أسئلة الاختيار من متعدد والأسئلة الكتابية، ويبلغ مجموع درجاته 100 درجة.', 20);
INSERT INTO dbo.TestTypes( TestTypeID, TestTypeTitle, TestTypeTitleAR, TestTypeDescription, TestTypeDescriptionAR, TestTypeFees ) VALUES ( 3, 'Driving Test', 'اختبار القيادة', 'This test evaluates the applicant''s driving skills and ability to operate a motor vehicle safely on public roads. A licensed examiner will induct this test with the applicant and finally decide on whether the applicant should pass or fail.', 'يقيس هذا الاختبار مهارات القيادة لدى المتقدم وقدرته على قيادة المركبة بأمان على الطرق العامة. سيُجري فاحصٌ مُرخص هذا الاختبار مع المتقدم، ويُقرر في النهاية ما إذا كان سيجتازه أم لا.', 30);
